// src/pages/dashboard/InstructorDashboard.js
import React from "react";
import Layout from "../../components/layout/Layout";

function InstructorDashboard() {
  return (
    <Layout pageTitle="Instructor Dashboard - NexaLearn LMS">
      <h1 className="mb-4" style={{ color: "#f59e0b", fontWeight: "700" }}>
        Instructor Dashboard
      </h1>

      <div className="row g-4">
        <div className="col-md-6">
          <div className="card shadow-sm p-3" style={{ borderLeft: "5px solid #f59e0b", borderRadius: "10px" }}>
            <h5 className="card-title text-secondary">Your Courses</h5>
            <p className="display-5 fw-bold">12</p>
            <p className="text-success">+1 this week</p>
          </div>
        </div>

        <div className="col-md-6">
          <div className="card shadow-sm p-3" style={{ borderLeft: "5px solid #3b82f6", borderRadius: "10px" }}>
            <h5 className="card-title text-secondary">Assignments Pending</h5>
            <p className="display-5 fw-bold">34</p>
            <p className="text-warning">Needs grading</p>
          </div>
        </div>
      </div>
    </Layout>
  );
}

export default InstructorDashboard;
